#include <stdio.h>
#include <stdlib.h>
#include <stdint.h>
#include <time.h>
#include <string.h>
#include <wiringPiI2C.h>
#include <wiringPi.h>

// Si1133 I2C address
#define SI1133_ADDR 0x60

// Si1133 register addresses
#define SI1133_REG_PART_ID 0x00
#define SI1133_REG_UVI 0x33
#define SI1133_REG_VIS_DATA0 0x22
#define SI1133_REG_IR_DATA0 0x24

// Function to read data from a specific register
int read_register(int fd, uint8_t reg) {
    int value = wiringPiI2CReadReg8(fd, reg);
    if (value == -1) {
        fprintf(stderr, "Error reading register 0x%02X\n", reg);
        return -1; // Indicate an error
    }
    return value;
}

// Function to write data to a specific register
int write_register(int fd, uint8_t reg, uint8_t value) {
    int result = wiringPiI2CWriteReg8(fd, reg, value);
    if (result == -1) {
        fprintf(stderr, "Error writing to register 0x%02X\n", reg);
        return -1; // Indicate an error
    }
    return 0; // Indicate success
}

// Function to read sensor data
int read_sensor_data(int fd, float *uv_index, int *visible_light, int *infrared_light) {
    int uvi = read_register(fd, SI1133_REG_UVI);
    int vis_low = read_register(fd, SI1133_REG_VIS_DATA0);
    int vis_high = read_register(fd, SI1133_REG_VIS_DATA0 + 1);
    int ir_low = read_register(fd, SI1133_REG_IR_DATA0);
    int ir_high = read_register(fd, SI1133_REG_IR_DATA0 + 1);

    if (uvi == -1 || vis_low == -1 || vis_high == -1 || ir_low == -1 || ir_high == -1) {
        return -1; // Indicate an error
    }

    *visible_light = (vis_high << 8) | vis_low;
    *infrared_light = (ir_high << 8) | ir_low;
    *uv_index = (float)uvi / 10.0; // Example conversion, adjust as needed

    return 0; // Indicate success
}

// Function to log sensor data to a file
void log_sensor_data(float uv_index, int visible_light, int infrared_light) {
    time_t t = time(NULL);
    struct tm tm = *localtime(&t);
    char timestamp[20];
    strftime(timestamp, sizeof(timestamp), "%Y-%m-%d %H:%M:%S", &tm);

    FILE *fp = fopen("light_data.log", "a");
    if (fp == NULL) {
        fprintf(stderr, "Error opening log file!\n");
        return;
    }

    fprintf(fp, "%s, UV Index: %.2f, Visible Light: %d, Infrared Light: %d\n", timestamp, uv_index, visible_light, infrared_light);
    fclose(fp);
}

int main() {
    int fd;
    float uv_index;
    int visible_light, infrared_light;

    wiringPiSetup();
    fd = wiringPiI2CSetup(SI1133_ADDR);
    if (fd == -1) {
        fprintf(stderr, "Error initializing I2C communication!\n");
        return 1;
    }

    while (1) {
        if (read_sensor_data(fd, &uv_index, &visible_light, &infrared_light) == 0) {
            log_sensor_data(uv_index, visible_light, infrared_light);
            printf("UV Index: %.2f, Visible Light: %d, Infrared Light: %d\n", uv_index, visible_light, infrared_light);
        } else {
            fprintf(stderr, "Error reading sensor data!\n");
        }

        delay(5000); // Wait 5 seconds
    }

    return 0;
}

