// Si1133 I2C address
#define SI1133_ADDR 0x60

// Si1133 register addresses
#define SI1133_REG_PART_ID 0x00
#define SI1133_REG_ALS_VIS_DATA0 0x22
#define SI1133_REG_ALS_VIS_DATA1 0x23
#define SI1133_REG_UV_INDEX0 0x2C
#define SI1133_REG_UV_INDEX1 0x2D
#define SI1133_REG_PARAM_WR 0x80

// Function to initialize the Si1133 sensor
int si1133_init(int fd) {
    // Reset the sensor
    if (wiringPiI2CWriteReg8(fd, SI1133_REG_PARAM_WR, 0x01) < 0) {
        fprintf(stderr, "Error resetting Si1133\n");
        return -1;
    }
    delay(10);

    // Configure the sensor for UV and ALS measurement
    if (wiringPiI2CWriteReg8(fd, SI1133_REG_PARAM_WR, 0x02) < 0) {
        fprintf(stderr, "Error configuring Si1133\n");
        return -1;
    }

    return 0;
}

// Function to read UV, ALS, and IR data from the Si1133 sensor
int si1133_read_data(int fd, float *uv, float *als, float *ir) {
    int uv_index0, uv_index1, als_vis_data0, als_vis_data1;

    uv_index0 = wiringPiI2CReadReg8(fd, SI1133_REG_UV_INDEX0);
    uv_index1 = wiringPiI2CReadReg8(fd, SI1133_REG_UV_INDEX1);
    als_vis_data0 = wiringPiI2CReadReg8(fd, SI1133_REG_ALS_VIS_DATA0);
    als_vis_data1 = wiringPiI2CReadReg8(fd, SI1133_REG_ALS_VIS_DATA1);

    if (uv_index0 == -1 || uv_index1 == -1 || als_vis_data0 == -1 || als_vis_data1 == -1) {
        fprintf(stderr, "Error reading data from Si1133\n");
        return -1;
    }

    *uv = (float)((uv_index1 << 8) | uv_index0);
    *als = (float)((als_vis_data1 << 8) | als_vis_data0);
    *ir = 0.0; // Not implemented in Si1133

    return 0;
}

// Function to get the current date and time as a string
char* get_timestamp() {
    time_t rawtime;
    struct tm *timeinfo;
    static char timestamp[20]; // Static to persist across calls

    time(&rawtime);
    timeinfo = localtime(&rawtime);

    strftime(timestamp, sizeof(timestamp), "%Y-%m-%d %H:%M:%S", timeinfo);
    return timestamp;
}

// Function to log data to a file
void log_data(const char *timestamp, float uv, float als, float ir) {
    FILE *fp = fopen("light_data.log", "a");
    if (fp == NULL) {
        fprintf(stderr, "Error opening log file\n");
        return;
    }

    fprintf(fp, "%s,%.2f,%.2f,%.2f\n", timestamp, uv, als, ir);
    fclose(fp);
}

