    if (wiringPiSetup() == -1) {
        fprintf(stderr, "wiringPiSetup failed\n");
        return 1;
    }

    // Initialize I2C
    fd = wiringPiI2CSetup(SI1133_ADDR);
    if (fd == -1) {
        fprintf(stderr, "wiringPiI2CSetup failed\n");
        return 1;
    }

    // Initialize the sensor
    if (si1133_init(fd) == -1) {
        fprintf(stderr, "Si1133 initialization failed\n");
        return 1;
    }

    printf("Starting data collection...\n");

    while (1) {
        timestamp = get_timestamp();
        if (si1133_read_data(fd, &uv, &als, &ir) == -1) {
