        } else {
            log_data(timestamp, uv, als, ir);
            printf("Timestamp: %s, UV: %.2f, ALS: %.2f, IR: %.2f\n", timestamp, uv, als, ir);
        }

        delay(1000); // Sample every 1 second
    }

