void motion_detected_callback(int gpio, int level, uint32_t tick) {
    if (level == 1) { // Rising edge detected (motion detected)
        printf("Motion detected!\n");
        gpioWrite(BUZZER_PIN, 1); // Activate buzzer
        gpioDelay(1000);          // Keep buzzer on for 1 second
        gpioWrite(BUZZER_PIN, 0); // Deactivate buzzer
