#include <string.h>

// Define constants
#define I2C_BUS "/dev/i2c-1" // I2C bus device file
#define LM75B_ADDR 0x48       // LM75B I2C address
#define GPIO_FAN 18           // GPIO pin for PWM fan control
#define TEMP_THRESHOLD 60     // Temperature threshold in Celsius
#define PWM_FREQUENCY 100     // PWM frequency in Hz
#define BUFFER_SIZE 10        // Size of the circular buffer

// Global variables (to be minimized, but needed for signal handling)
static int i2c_fd = -1;
static int running = 1;

// Circular buffer structure
typedef struct {
    float temperatures[BUFFER_SIZE];
    int duty_cycles[BUFFER_SIZE];
    int head;
    int count;
} CircularBuffer;

// Function prototypes
int i2c_read_temperature(int fd);
float convert_to_celsius(unsigned short raw_temp);
void set_fan_speed(int gpio_pin, int duty_cycle);
void add_to_buffer(CircularBuffer *buffer, float temperature, int duty_cycle);
void print_buffer(CircularBuffer *buffer);
void signal_handler(int signal);
void cleanup();

// Initialize the circular buffer
void init_circular_buffer(CircularBuffer *buffer) {
    buffer->head = 0;
    buffer->count = 0;
}

// I2C read temperature function
int i2c_read_temperature(int fd) {
    unsigned char buf[2];
    int result;

    result = read(fd, buf, 2);
    if (result != 2) {
        fprintf(stderr, "Error reading temperature data from I2C\n");
        return -1; // Indicate an error
    }

    return ((buf[0] << 8) | buf[1]); // Combine the two bytes
}

// Temperature conversion function
float convert_to_celsius(unsigned short raw_temp) {
    // LM75B returns MSB first, so swap bytes
    raw_temp = (raw_temp >> 8) | (raw_temp << 8);
    return (float)(short)raw_temp * 0.0625; // Each bit is 0.0625 degrees C
}

// Fan speed control function
void set_fan_speed(int gpio_pin, int duty_cycle) {
    if (duty_cycle < 0) duty_cycle = 0;
    if (duty_cycle > 255) duty_cycle = 255;
    gpioPWM(gpio_pin, duty_cycle);
}

// Buffer manipulation functions
void add_to_buffer(CircularBuffer *buffer, float temperature, int duty_cycle) {
    buffer->temperatures[buffer->head] = temperature;
    buffer->duty_cycles[buffer->head] = duty_cycle;
    buffer->head = (buffer->head + 1) % BUFFER_SIZE;
    if (buffer->count < BUFFER_SIZE) {
        buffer->count++;
    }
}

void print_buffer(CircularBuffer *buffer) {
    printf("\n--- Buffer Contents ---\n");
    for (int i = 0; i < buffer->count; i++) {
        int index = (buffer->head - buffer->count + i + BUFFER_SIZE) % BUFFER_SIZE; // Corrected index calculation
        printf("Index: %d, Temp: %.2f C, Duty Cycle: %d\n", i, buffer->temperatures[index], buffer->duty_cycles[index]);
    }
    printf("----------------------\n");
}

// Signal handler for graceful shutdown
void signal_handler(int signal) {
    running = 0;
    printf("Caught signal %d, exiting gracefully...\n", signal);
}

// Cleanup function to release resources
void cleanup() {
    if (i2c_fd != -1) {
        close(i2c_fd);
    }
    gpioTerminate();
    printf("Resources released.\n");
}

int main() {
    CircularBuffer buffer;
    int duty_cycle;
    float temperature;
    unsigned short raw_temp;
    time_t now;
    struct tm *timeinfo;
    char timestamp[20];

    // Initialize pigpio
    if (gpioInitialise() < 0) {
        fprintf(stderr, "pigpio initialisation failed\n");
        return 1;
    }

    // Set GPIO 18 as output
    gpioSetMode(GPIO_FAN, PI_OUTPUT);
    gpioSetPWMfrequency(GPIO_FAN, PWM_FREQUENCY);

    // Initialize I2C
    i2c_fd = open(I2C_BUS, O_RDWR);
    if (i2c_fd < 0) {
        fprintf(stderr, "Error opening I2C device\n");
        gpioTerminate();
        return 1;
    }

    if (ioctl(i2c_fd, I2C_SLAVE, LM75B_ADDR) < 0) {
        fprintf(stderr, "Error setting I2C slave address\n");
        close(i2c_fd);
        gpioTerminate();
        return 1;
    }

    // Initialize circular buffer
    init_circular_buffer(&buffer);

    // Set up signal handling
    signal(SIGINT, signal_handler);

    printf("Temperature monitoring and fan control started. Press Ctrl+C to exit.\n");

    while (running) {
        // Read temperature
        raw_temp = i2c_read_temperature(i2c_fd);
        if (raw_temp == -1) {
            fprintf(stderr, "Failed to read temperature, using previous value.\n");
            // Consider implementing a fallback mechanism or error handling
            // In a critical system, you might want to exit or try again later
        } else {
            temperature = convert_to_celsius(raw_temp);

            // Control fan speed based on temperature
            if (temperature > TEMP_THRESHOLD) {
                duty_cycle = 255; // Full speed
            } else {
                duty_cycle = 0;    // Stop the fan
            }

            set_fan_speed(GPIO_FAN, duty_cycle);

            // Add to circular buffer
            add_to_buffer(&buffer, temperature, duty_cycle);

            // Get current timestamp
            time(&now);
            timeinfo = localtime(&now);
            strftime(timestamp, sizeof(timestamp), "%Y-%m-%d %H:%M:%S", timeinfo);

            // Print current status
            printf("%s - Temperature: %.2f C, Duty Cycle: %d\n", timestamp, temperature, duty_cycle);
        }

        // Print the buffer periodically (e.g., every 5 seconds)
        if (time(&now) % 5 == 0) {
            print_buffer(&buffer);
        }

        sleep(1); // Check every 1 second
    }

    cleanup();
    return 0;
}

