        return -1;
    }
    return 0;
}

// Open I2C device
int open_i2c_device(int addr) {
    i2c_handle = i2cOpen(1, addr, 0);
    if (i2c_handle < 0) {
        fprintf(stderr, "Failed to open I2C device: %d\n", i2c_handle);
        return -1;
    }
    return 0;
}

// Read temperature from LM75B sensor
float read_temperature() {
    char buf[2];
    int result = i2cReadDevice(i2c_handle, buf, 2);
    if (result != 2) {
        fprintf(stderr, "Failed to read temperature: %d\n", result);
        return -1000.0; // Indicate error
    }

    int16_t raw_temp = (buf[0] << 8) | buf[1];
    if (raw_temp & 0x8000) {
        raw_temp |= 0xFFFF0000; // Sign extend for negative temperatures
    }
    float temperature = (float)raw_temp * 0.0625;
    return temperature;
}

// Set fan speed using PWM
void set_fan_speed(int speed) {
    if (speed < 0) speed = 0;
    if (speed > 255) speed = 255;
    gpioPWM(FAN_GPIO, speed);
}

// Add data point to circular buffer
void add_data_point(float temperature, int fan_speed) {
    time(&data_buffer[buffer_index].timestamp);
    data_buffer[buffer_index].temperature = temperature;
    data_buffer[buffer_index].fan_speed = fan_speed;
    buffer_index = (buffer_index + 1) % BUFFER_SIZE;
}

// Print data point
void print_data_point(DataPoint point) {
    char timestamp_str[30];
    ctime_r(&point.timestamp, timestamp_str);
    timestamp_str[strlen(timestamp_str) - 1] = '\0'; // Remove trailing newline
    printf("%s - Temperature: %.2f C, Fan Speed: %d\n", timestamp_str, point.temperature, point.fan_speed);
}

// Signal handler for graceful shutdown
void signal_handler(int signal) {
    running = 0;
    printf("Caught signal %d, exiting gracefully...\n", signal);
}

// Cleanup resources
void cleanup() {
    if (i2c_handle >= 0) {
        i2cClose(i2c_handle);
    }
    gpioTerminate();
    printf("Cleanup complete.\n");
}

