    // Initialize pigpio
    if (init_pigpio() != 0) {
        return 1;
    }

    // Open I2C device
    if (open_i2c_device(I2C_ADDR) != 0) {
        cleanup();
        return 1;
    }

    // Configure FAN_GPIO as output
    gpioSetMode(FAN_GPIO, PI_OUTPUT);
    gpioSetPWMfrequency(FAN_GPIO, PWM_FREQ);

    // Set initial fan speed to 0
    set_fan_speed(0);

    // Install signal handler
    signal(SIGINT, signal_handler);
    signal(SIGTERM, signal_handler);

    printf("Temperature monitoring and fan control started. Press Ctrl+C to exit.\n");

    while (running) {
        float temperature = read_temperature();

        if (temperature > -999.0) { // Check for read error
            int fan_speed = 0;
            if (temperature < TEMP_THRESHOLD_LOW) {
                fan_speed = 0;
            } else if (temperature > TEMP_THRESHOLD_HIGH) {
                fan_speed = 255;
            } else {
                fan_speed = (int)((temperature - TEMP_THRESHOLD_LOW) * 255.0 / (TEMP_THRESHOLD_HIGH - TEMP_THRESHOLD_LOW));
            }

            set_fan_speed(fan_speed);
            add_data_point(temperature, fan_speed);
        } else {
            fprintf(stderr, "Failed to read temperature. Retrying in 1 second.\n");
        }

        sleep(1);
    }

    // Cleanup and exit
    cleanup();
    return 0;
