    unsigned char data[4];
    int result;

    result = wiringPiSPIDataRW(channel, data, 4);
    if (result == -1) {
        fprintf(stderr, "SPI read failed: %s\n", strerror(errno));
        return -1; // Indicate error
    }

    // Check for fault bits (bit 2 of byte 3)
    if (data[3] & 0x04) {
        fprintf(stderr, "MAX31855 Fault detected!\n");
        if (data[3] & 0x01) {
