        } else if (data[3] & 0x02) {
            fprintf(stderr, "Thermocouple shorted to GND\n");
        } else if (data[3] & 0x04) {
            fprintf(stderr, "Thermocouple shorted to VCC\n");
        }
        return -1; // Indicate error
    }

    // Extract thermocouple temperature (bits 3-18 of bytes 0 and 1)
    int16_t thermocouple_data = ((data[0] << 8) | data[1]) >> 3;
    return thermocouple_data;
}

