    if (temperature < TEMP_MIN) {
        return DUTY_CYCLE_MIN;
    } else if (temperature > TEMP_MAX) {
        return DUTY_CYCLE_MAX;
    } else {
        // Linear mapping between temperature and duty cycle
        float duty_cycle_float = (temperature - TEMP_MIN) / (TEMP_MAX - TEMP_MIN) * (DUTY_CYCLE_MAX - DUTY_CYCLE_MIN) + DUTY_CYCLE_MIN;
        return (int)duty_cycle_float;
    }
