#include <stdlib.h>
#include <stdint.h>
#include <wiringPi.h>
#include <wiringPiSPI.h>
#include <time.h>
#include <signal.h>
#include <string.h>

// Define constants
#define SPI_CHANNEL 0
#define SPI_SPEED 1000000 // 1 MHz
#define FAN_PIN 18         // GPIO18 (PWM0)
#define PWM_RANGE 1024      // PWM range (0-1023)

// Global variable for graceful shutdown
volatile sig_atomic_t program_running = 1;

// Function prototypes
int init_spi();
int init_pwm();
int read_max31855(int *thermocouple_temp, int *internal_temp);
float calculate_average_temp(int thermocouple_temp, int internal_temp);
int set_fan_speed(int speed);
int log_data(float average_temp, int fan_speed);
void signal_handler(int signal);

// Signal handler for graceful shutdown
void signal_handler(int signal) {
    if (signal == SIGINT) {
        printf("Caught SIGINT, exiting gracefully.\n");
        program_running = 0;
        set_fan_speed(0); // Stop the fan
        exit(0);
    }
}

// Initialize SPI communication
int init_spi() {
    if (wiringPiSPISetup(SPI_CHANNEL, SPI_SPEED) == -1) {
        fprintf(stderr, "Error initializing SPI.\n");
        return -1;
    }
    return 0;
}

// Initialize PWM on GPIO18
int init_pwm() {
    pinMode(FAN_PIN, PWM_OUTPUT);
    pwmSetMode(PWM_MODE_MS);
    pwmSetRange(PWM_RANGE);
    pwmSetClock(192); // Adjust clock for desired PWM frequency
    return 0;
}

// Read temperature data from MAX31855
int read_max31855(int *thermocouple_temp, int *internal_temp) {
    unsigned char data[4];
    int i;

    if (wiringPiSPIDataRW(SPI_CHANNEL, data, 4) == -1) {
        fprintf(stderr, "Error reading SPI data.\n");
        return -1; // Indicate error
    }

    // Check for fault bits
    if (data[3] & 0x07) {
        fprintf(stderr, "MAX31855 Fault detected: 0x%02X\n", data[3]);
        return -1; // Indicate error
    }

    // Extract thermocouple temperature (bits 31:18)
    *thermocouple_temp = ((data[0] << 6) | (data[1] >> 2)) >> 2;

    // Extract internal temperature (bits 15:4)
    *internal_temp = ((data[1] << 4) | (data[2] >> 4)) >> 4;

    return 0; // Indicate success
}

// Calculate average temperature
float calculate_average_temp(int thermocouple_temp, int internal_temp) {
    return (thermocouple_temp + internal_temp) / 2.0;
}

// Set fan speed using PWM
int set_fan_speed(int speed) {
    if (speed < 0) speed = 0;
    if (speed > 100) speed = 100;
    pwmWrite(FAN_PIN, speed * (PWM_RANGE / 100)); // Scale speed to PWM range
    return 0;
}

// Log data to file
int log_data(float average_temp, int fan_speed) {
    FILE *fp = fopen("fan_log.txt", "a");
    if (fp == NULL) {
        fprintf(stderr, "Error opening log file.\n");
        return -1;
    }

    time_t t = time(NULL);
    struct tm tm = *localtime(&t);
    char timestamp[20];
    strftime(timestamp, sizeof(timestamp), "%Y-%m-%d %H:%M:%S", &tm);

    fprintf(fp, "%s, Average Temp: %.2f C, Fan Speed: %d%%\n", timestamp, average_temp, fan_speed);
    fclose(fp);
    return 0;
}

int main() {
    int thermocouple_temp, internal_temp;
    float average_temp;
    int fan_speed;

    // Set up signal handler for Ctrl+C
    signal(SIGINT, signal_handler);

    // Initialize wiringPi
    if (wiringPiSetup() == -1) {
        fprintf(stderr, "Error initializing wiringPi.\n");
        return 1;
    }

    // Initialize SPI
    if (init_spi() == -1) {
        return 1;
    }

    // Initialize PWM
    if (init_pwm() == -1) {
        return 1;
    }

    printf("Temperature monitoring and fan control started. Press Ctrl+C to exit.\n");

    while (program_running) {
        if (read_max31855(&thermocouple_temp, &internal_temp) == 0) {
            average_temp = calculate_average_temp(thermocouple_temp, internal_temp);
            fan_speed = 0;
            if (average_temp > 25.0) {
                fan_speed = (int)((average_temp - 25.0) / 5.0 * 100); // Scale fan speed
                if (fan_speed > 100) fan_speed = 100;
            }

            if (set_fan_speed(fan_speed) == 0) {
                log_data(average_temp, fan_speed);
                printf("Average Temp: %.2f C, Fan Speed: %d%%\n", average_temp, fan_speed);
            } else {
                fprintf(stderr, "Error setting fan speed.\n");
            }
        } else {
            fprintf(stderr, "Error reading thermocouple data.\n");
        }

        delay(1000); // Check every 1 second
    }

    return 0;
}

/*
 * Distributed System Considerations:
 *
 * This code can be adapted for a distributed system by using
 * UART (serial communication) to transmit temperature data from the Raspberry Pi
 * Zero W to a central server. The `read_max31855()` function would read the data
 * from the MAX31855, and then transmit it over UART. The central server would
 * then process the data and control the fan as needed.
 *
 * To implement this, you would need to:
 * 1. Initialize UART communication using `wiringPiSerialSetup()`.
 * 2. In `read_max31855()`, read the data from the MAX31855 as before, but
 *    instead of logging the data, transmit it over UART.
 * 3. On the central server, open a serial port and read the data from the Raspberry Pi.
 * 4. Process the data and control the fan.
 */

