#include <stdio.h>
#include <stdlib.h>
#include <wiringPi.h>
#include <wiringPiSPI.h>
#include <time.h>
#include <signal.h>
#include <errno.h>

// Constants
#define SPI_CHANNEL 0
#define SPI_SPEED 1000000 // 1 MHz
#define ADC_CHANNEL 0      // AWM5300V outputs on channel 0 of ADC
#define ALARM_PIN 1         // GPIO pin for alarm
#define THRESHOLD 0.5      // Voltage threshold for alarm
#define LOG_FILE "airflow_log.txt"

// Global variables
FILE *log_file = NULL;

// Function prototypes
float read_adc(int channel);
float adc_to_voltage(float adc_value);
void log_data(float voltage);
void alarm_on();
void alarm_off();
void signal_handler(int signal);

// Signal handler for graceful shutdown
void signal_handler(int signal) {
    printf("Caught signal %d, cleaning up...\n", signal);
    if (log_file != NULL) {
        fclose(log_file);
    }
    alarm_off(); // Ensure alarm is off
    exit(0);
}

// Function to read from MCP3008 ADC
float read_adc(int channel) {
    if (channel < 0 || channel > 7) {
        fprintf(stderr, "Error: Invalid ADC channel %d\n", channel);
        return -1.0; // Indicate error
    }

    unsigned char buffer[3];
    buffer[0] = 0x01; // Start bit
    buffer[1] = (0x08 | channel) << 4; // Single-ended mode, channel select
    buffer[2] = 0x00;

    wiringPiSPIDataRW(SPI_CHANNEL, buffer, 3);

    int adc_value = ((buffer[1] & 0x03) << 8) + buffer[2];
    return (float)adc_value;
}

// Function to convert ADC value to voltage
float adc_to_voltage(float adc_value) {
    return (adc_value / 1023.0) * 3.3;
}

// Function to log voltage data to file
void log_data(float voltage) {
    time_t t = time(NULL);
    struct tm tm = *localtime(&t);
    char timestamp[20];
    strftime(timestamp, sizeof(timestamp), "%Y-%m-%d %H:%M:%S", &tm);

    log_file = fopen(LOG_FILE, "a");
    if (log_file == NULL) {
        fprintf(stderr, "Error opening log file: %s\n", strerror(errno));
        return;
    }

    fprintf(log_file, "%s, %.3f\n", timestamp, voltage);
    fclose(log_file);
}

// Function to activate the alarm
void alarm_on() {
    digitalWrite(ALARM_PIN, HIGH);
    printf("Alarm ON!\n");
}

// Function to deactivate the alarm
void alarm_off() {
    digitalWrite(ALARM_PIN, LOW);
    printf("Alarm OFF!\n");
}

int main() {
    // Initialize wiringPi
    if (wiringPiSetup() == -1) {
        fprintf(stderr, "Error initializing wiringPi: %s\n", strerror(errno));
        return 1;
    }

    // Initialize SPI
    if (wiringPiSPISetup(SPI_CHANNEL, SPI_SPEED) == -1) {
        fprintf(stderr, "Error initializing SPI: %s\n", strerror(errno));
        return 1;
    }

    // Set alarm pin as output
    pinMode(ALARM_PIN, OUTPUT);
    alarm_off(); // Ensure alarm is off initially

    // Set up signal handler for Ctrl+C
    signal(SIGINT, signal_handler);

    printf("Airflow monitoring started. Press Ctrl+C to exit.\n");

    while (1) {
        float adc_value = read_adc(ADC_CHANNEL);
        if (adc_value >= 0) {
            float voltage = adc_to_voltage(adc_value);
            log_data(voltage);

            if (voltage < THRESHOLD) {
                alarm_on();
            } else {
