    if (control_lock(LOCK1_PIN, UNLOCKED) != 0) {
        fprintf(stderr, "Failed to initialize lock 1 to UNLOCKED\n");
        gpioTerminate();
        return 1;
    }
    if (control_lock(LOCK2_PIN, UNLOCKED) != 0) {
        fprintf(stderr, "Failed to initialize lock 2 to UNLOCKED\n");
        gpioTerminate();
        return 1;
    }

    return 0; // Indicate success
}

