void cleanup() {
    if (i2c_handle >= 0) {
        i2cClose(i2c_handle);
    }
    if (log_file != NULL) {
        fclose(log_file);
    }
    gpioPWM(LED_GPIO, 0); // Turn off LED
    gpioTerminate();
}

